SELECT [Reserv__Assign_ Link].[Reserv__Assign_ Type], [Reserv__Assign_ Link].[Sales Document No_] AS OrdineNumero, [Reserv__Assign_ Link].[Sales Line No_] AS OrdineRiga, [Reserv__Assign_ Link].[Source Document No_], [Reserv__Assign_ Link].[Source Line No_], [Reserv__Assign_ Link].No_, [Reserv__Assign_ Link].[Constant Variable Code], [Reserv__Assign_ Link].[Assortment Code], Val([Reserved_Assigned Quantity]) AS assortmentQty, [Reserv__Assign_ Link].Type, [Reserv__Assign_ Link].[Source Type], "PREN-GIA" AS statusRiga, [Reserv__Assign_ Link].[Selling Season Code] AS [Season Code], [Reserv__Assign_ Link].[Date Reservation]
FROM [Reserv__Assign_ Link]
WHERE ((([Reserv__Assign_ Link].[Reserv__Assign_ Type])=1) AND (([Reserv__Assign_ Link].No_)="F5MURRAY01/LES") AND (([Reserv__Assign_ Link].[Constant Variable Code])="NVY/GRY") AND (([Reserv__Assign_ Link].[Assortment Code])="BM01" Or ([Reserv__Assign_ Link].[Assortment Code])="BM08") AND ((Val([Reserved_Assigned Quantity]))<>0) AND (([Reserv__Assign_ Link].Type)=20) AND (([Reserv__Assign_ Link].[Source Type])=0) AND (([Reserv__Assign_ Link].[Selling Season Code])=[forms]![principale]![filtroStagioneprenotazioni])) OR ((([Reserv__Assign_ Link].No_)="F5OLYMPIA11/GLI") AND (([Reserv__Assign_ Link].[Constant Variable Code])="DKB") AND (([Reserv__Assign_ Link].[Assortment Code])="BW07" Or ([Reserv__Assign_ Link].[Assortment Code])="BW08"));

